import org.apache.kafka.clients.producer.*;
import org.apache.kafka.common.header.Header;
import org.apache.kafka.common.header.internals.RecordHeader;
import org.apache.kafka.common.serialization.StringSerializer;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.nio.charset.StandardCharsets;
import java.util.*;
import java.util.concurrent.ExecutionException;

@SpringBootApplication
public class KafkaProducerApplication {
    public static void main(String[] args) {
        SpringApplication.run(KafkaProducerApplication.class, args);
    }

    @Bean
    public KafkaProducer<String, String> kafkaProducer() {
        Properties props = new Properties();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.ACKS_CONFIG, "all");
        props.put(ProducerConfig.RETRIES_CONFIG, 3);
        props.put(ProducerConfig.LINGER_MS_CONFIG, 1);
        return new KafkaProducer<>(props);
    }
}

@RestController
@RequestMapping("/api/events")
class EventProducerController {

    private final KafkaProducer<String, String> producer;

    public EventProducerController(KafkaProducer<String, String> producer) {
        this.producer = producer;
    }

    @PostMapping("/send")
    public ResponseEntity<EventResponse> sendEvent(@RequestBody EventRequest request) {
        try {
            ProducerRecord<String, String> record = createProducerRecord(request);
            RecordMetadata metadata = producer.send(record).get();
            
            EventResponse response = new EventResponse(
                true,
                "Event sent successfully",
                metadata.topic(),
                metadata.partition(),
                metadata.offset(),
                metadata.timestamp()
            );
            
            return ResponseEntity.ok(response);
        } catch (InterruptedException | ExecutionException e) {
            return ResponseEntity.internalServerError()
                .body(new EventResponse(false, "Failed to send event: " + e.getMessage(), null, null, null, null));
        }
    }

    @PostMapping("/send-async")
    public ResponseEntity<Map<String, String>> sendEventAsync(@RequestBody EventRequest request) {
        ProducerRecord<String, String> record = createProducerRecord(request);
        
        producer.send(record, new Callback() {
            @Override
            public void onCompletion(RecordMetadata metadata, Exception exception) {
                if (exception != null) {
                    System.err.println("Error sending event: " + exception.getMessage());
                } else {
                    System.out.println("Event sent successfully to topic: " + metadata.topic() + 
                        ", partition: " + metadata.partition() + 
                        ", offset: " + metadata.offset());
                }
            }
        });
        
        Map<String, String> response = new HashMap<>();
        response.put("status", "accepted");
        response.put("message", "Event queued for sending");
        return ResponseEntity.accepted().body(response);
    }

    @PostMapping("/send-batch")
    public ResponseEntity<BatchEventResponse> sendBatchEvents(@RequestBody BatchEventRequest request) {
        List<EventResult> results = new ArrayList<>();
        int successCount = 0;
        int failureCount = 0;

        for (EventRequest event : request.getEvents()) {
            try {
                ProducerRecord<String, String> record = createProducerRecord(event);
                RecordMetadata metadata = producer.send(record).get();
                results.add(new EventResult(true, "Success", metadata.offset()));
                successCount++;
            } catch (Exception e) {
                results.add(new EventResult(false, e.getMessage(), null));
                failureCount++;
            }
        }

        BatchEventResponse response = new BatchEventResponse(
            successCount,
            failureCount,
            results
        );

        return ResponseEntity.ok(response);
    }

    private ProducerRecord<String, String> createProducerRecord(EventRequest request) {
        String topic = request.getTopic() != null ? request.getTopic() : "default-events";
        String key = request.getKey();
        String value = request.getMessage();

        ProducerRecord<String, String> record = new ProducerRecord<>(topic, key, value);

        if (request.getTrackingId() != null) {
            record.headers().add(new RecordHeader("tracking-id", 
                request.getTrackingId().getBytes(StandardCharsets.UTF_8)));
        }

        if (request.getUserId() != null) {
            record.headers().add(new RecordHeader("user-id", 
                request.getUserId().getBytes(StandardCharsets.UTF_8)));
        }

        if (request.getHeaders() != null && !request.getHeaders().isEmpty()) {
            for (Map.Entry<String, String> entry : request.getHeaders().entrySet()) {
                record.headers().add(new RecordHeader(entry.getKey(), 
                    entry.getValue().getBytes(StandardCharsets.UTF_8)));
            }
        }

        record.headers().add(new RecordHeader("timestamp", 
            String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8)));
        
        record.headers().add(new RecordHeader("source", 
            "event-tracking-api".getBytes(StandardCharsets.UTF_8)));

        return record;
    }
}

